    count(*) AS error_count,
    max("timestamp") AS last_occurrence,
    count(DISTINCT user_id) AS affected_users
   FROM public.error_logs
  WHERE ("timestamp" > (now() - '24:00:00'::interval))
  GROUP BY error_type
  ORDER BY (count(*)) DESC;


